// PARSER JULIA OUTPUT + SSE
// Esse node:
// 1. lê SSE bruto em $json.data
// 2. extrai a resposta final da Julia
// 3. parseia as tags estruturadas
// 4. preserva memória anterior quando vier vazio
// 5. marca erro quando a resposta da IA vier vazia, inválida ou fraca

function safeString(v) {
  return v === undefined || v === null ? '' : String(v);
}

function isPlaceholder(value) {
  return /\{\{.*\}\}/.test(String(value || '').trim());
}

function keepOldIfEmpty(newValue, oldValue) {
  const n = safeString(newValue).trim();
  const o = safeString(oldValue).trim();

  if (n === '' || isPlaceholder(n)) return o;
  return n;
}

function normalizeEmail(email) {
  return safeString(email).trim().toLowerCase();
}

function extractTag(text, tagName) {
  const regex = new RegExp(`^#${tagName}:(.*)$`, 'mi');
  const match = safeString(text).match(regex);
  return match ? match[1].trim() : '';
}

function cleanMessage(text) {
  return safeString(text)
    .replace(/^#STATUS:.*$/gmi, '')
    .replace(/^#LAST_INTENT:.*$/gmi, '')
    .replace(/^#LEAD_SUMMARY:.*$/gmi, '')
    .replace(/^#SELECTED_OPTION:.*$/gmi, '')
    .replace(/^#SELECTED_OPTION_START:.*$/gmi, '')
    .replace(/^#OPTION_1_START:.*$/gmi, '')
    .replace(/^#OPTION_2_START:.*$/gmi, '')
    .replace(/^#REQUESTED_DAY:.*$/gmi, '')
    .replace(/^#REQUESTED_DATE:.*$/gmi, '')
    .replace(/^#REQUESTED_PERIOD:.*$/gmi, '')
    .replace(/^#REQUESTED_TIME_MIN:.*$/gmi, '')
    .replace(/^#REQUESTED_TIME_MAX:.*$/gmi, '')
    .replace(/^#EMAIL:.*$/gmi, '')
    .replace(/^#SYSTEM_EVENT:.*$/gmi, '')
    .replace(/^#ERROR_FLAG:.*$/gmi, '')
    .replace(/^#ERROR_MESSAGE:.*$/gmi, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function parseSSE(raw) {
  const text = safeString(raw);

  const lines = text
    .split('\n')
    .map(line => line.trim())
    .filter(line => line.startsWith('data: '));

  const events = [];

  for (const line of lines) {
    const jsonStr = line.replace(/^data:\s*/, '').trim();

    if (!jsonStr.startsWith('{')) continue;

    try {
      events.push(JSON.parse(jsonStr));
    } catch (e) {
      // ignora eventos quebrados
    }
  }

  const workflowFinished = [...events].reverse().find(e => e.event === 'workflow_finished');
  const answerNodeFinished = [...events].reverse().find(
    e =>
      e.event === 'node_finished' &&
      e.data &&
      e.data.node_id === 'answer'
  );

  const llmNodeFinished = [...events].reverse().find(
    e =>
      e.event === 'node_finished' &&
      e.data &&
      e.data.node_id === 'llm'
  );

  const messageChunks = events
    .filter(e => e.event === 'message' && typeof e.answer === 'string')
    .map(e => e.answer);

  const finalAnswer =
    workflowFinished?.data?.outputs?.answer ||
    answerNodeFinished?.data?.outputs?.answer ||
    llmNodeFinished?.data?.outputs?.text ||
    messageChunks.join('').trim() ||
    '';

  const conversationId =
    workflowFinished?.conversation_id ||
    answerNodeFinished?.conversation_id ||
    llmNodeFinished?.conversation_id ||
    events.find(e => e.conversation_id)?.conversation_id ||
    '';

  const messageId =
    workflowFinished?.message_id ||
    answerNodeFinished?.message_id ||
    llmNodeFinished?.message_id ||
    events.find(e => e.message_id)?.message_id ||
    '';

  return {
    finalAnswer,
    conversationId,
    messageId,
    rawEventsCount: events.length,
  };
}

function hasMeaningfulContent(text) {
  const t = safeString(text).trim();
  if (!t) return false;

  const cleaned = cleanMessage(t)
    .replace(/\s+/g, ' ')
    .trim();

  return cleaned.length > 0;
}

function hasStructuredOutput(parsedObj) {
  return [
    parsedObj.lead_status,
    parsedObj.last_intent,
    parsedObj.lead_summary,
    parsedObj.selected_option,
    parsedObj.selected_option_start,
    parsedObj.option_1_start,
    parsedObj.option_2_start,
    parsedObj.requested_day,
    parsedObj.requested_date,
    parsedObj.requested_period,
    parsedObj.requested_time_min,
    parsedObj.requested_time_max,
    parsedObj.email,
    parsedObj.system_event,
  ].some(v => safeString(v).trim() !== '');
}

function isWeakLeadSummary(summary) {
  const s = safeString(summary).trim();
  if (!s) return true;

  const normalized = s
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();

  const weakPatterns = [
    'nome:; empresa:; nicho:',
    'nome:; empresa:',
    'nome:;',
  ];

  if (weakPatterns.some(p => normalized.includes(p))) return true;

  const stripped = normalized.replace(/[;:\s]/g, '');
  return stripped.length < 30;
}

const input = $json;

// 1. Tenta ler direto se já vier pronto
let rawOutput =
  input.answer ||
  input.output ||
  input.text ||
  input.message ||
  input.response ||
  '';

// 2. Se não veio direto, tenta extrair do SSE bruto em data
let conversationId = input.conversation_id || '';
let messageId = input.message_id || '';
let rawEventsCount = input.raw_events_count || 0;

if (!rawOutput && input.data) {
  const sse = parseSSE(input.data);
  rawOutput = sse.finalAnswer || '';
  conversationId = conversationId || sse.conversationId;
  messageId = messageId || sse.messageId;
  rawEventsCount = rawEventsCount || sse.rawEventsCount;
}

// 3. Memória anterior
const old = {
  lead_status: input.lead_status || input.last_known_status || '',
  last_intent: input.last_intent || '',
  lead_summary: input.lead_summary || input.last_known_summary || '',
  selected_option: input.selected_option || input.last_known_selected_option || '',
  selected_option_start: input.selected_option_start || input.last_known_selected_option_start || '',
  option_1_start: input.option_1_start || input.last_known_option_1_start || '',
  option_2_start: input.option_2_start || input.last_known_option_2_start || '',
  requested_day: input.requested_day || '',
  requested_date: input.requested_date || '',
  requested_period: input.requested_period || '',
  requested_time_min: input.requested_time_min || '',
  requested_time_max: input.requested_time_max || '',
  email: input.email || input.last_known_email || '',
};

// 4. Extrair tags
const parsed = {
  lead_status: extractTag(rawOutput, 'STATUS'),
  last_intent: extractTag(rawOutput, 'LAST_INTENT'),
  lead_summary: extractTag(rawOutput, 'LEAD_SUMMARY'),
  selected_option: extractTag(rawOutput, 'SELECTED_OPTION'),
  selected_option_start: extractTag(rawOutput, 'SELECTED_OPTION_START'),
  option_1_start: extractTag(rawOutput, 'OPTION_1_START'),
  option_2_start: extractTag(rawOutput, 'OPTION_2_START'),
  requested_day: extractTag(rawOutput, 'REQUESTED_DAY'),
  requested_date: extractTag(rawOutput, 'REQUESTED_DATE'),
  requested_period: extractTag(rawOutput, 'REQUESTED_PERIOD'),
  requested_time_min: extractTag(rawOutput, 'REQUESTED_TIME_MIN'),
  requested_time_max: extractTag(rawOutput, 'REQUESTED_TIME_MAX'),
  email: normalizeEmail(extractTag(rawOutput, 'EMAIL')),

  system_event: extractTag(rawOutput, 'SYSTEM_EVENT'),
  error_flag: extractTag(rawOutput, 'ERROR_FLAG'),
  error_message: extractTag(rawOutput, 'ERROR_MESSAGE'),
};

// 5. Validar se a resposta da IA é realmente útil
const meaningfulContent = hasMeaningfulContent(rawOutput);
const hasStructuredTags = hasStructuredOutput(parsed);
const weakSummary = isWeakLeadSummary(parsed.lead_summary);

const aiResponseInvalid =
  !meaningfulContent ||
  (!hasStructuredTags && !parsed.error_flag && !parsed.error_message) ||
  weakSummary;

// 6. Resultado consolidado
const result = {
  raw_output: rawOutput,
  answer: cleanMessage(rawOutput),

  dify_uuid: conversationId,
  message_id: messageId,
  raw_events_count: rawEventsCount,

  // ===== CORE SDR =====
  lead_status: keepOldIfEmpty(parsed.lead_status, old.lead_status) || 'QUALIFICANDO',
  last_intent: keepOldIfEmpty(parsed.last_intent, old.last_intent),
  lead_summary: keepOldIfEmpty(parsed.lead_summary, old.lead_summary),

  selected_option: keepOldIfEmpty(parsed.selected_option, old.selected_option),
  selected_option_start: keepOldIfEmpty(parsed.selected_option_start, old.selected_option_start),
  option_1_start: keepOldIfEmpty(parsed.option_1_start, old.option_1_start),
  option_2_start: keepOldIfEmpty(parsed.option_2_start, old.option_2_start),

  requested_day: keepOldIfEmpty(parsed.requested_day, old.requested_day),
  requested_date: keepOldIfEmpty(parsed.requested_date, old.requested_date),
  requested_period: keepOldIfEmpty(parsed.requested_period, old.requested_period),
  requested_time_min: keepOldIfEmpty(parsed.requested_time_min, old.requested_time_min),
  requested_time_max: keepOldIfEmpty(parsed.requested_time_max, old.requested_time_max),

  email: keepOldIfEmpty(parsed.email, old.email),

  // ===== CONTROLE DE FLUXO =====
  system_event: keepOldIfEmpty(
    parsed.system_event,
    safeString(input.system_event || input.last_system_event || '')
  ),

  error_flag: parsed.error_flag && safeString(parsed.error_flag).trim() !== ''
    ? safeString(parsed.error_flag).trim()
    : aiResponseInvalid ? 1 : 0,

  error_message: parsed.error_message && safeString(parsed.error_message).trim() !== ''
    ? safeString(parsed.error_message).trim()
    : aiResponseInvalid
      ? 'EMPTY_OR_INVALID_AI_RESPONSE'
      : safeString(input.error_message || ''),

  retry_count: Number(input.retry_count || 0),
};

return [{ json: result }];

